def solve(value: Array[Long], limit: Array[Long]): Long = {
    // Sort elements by value in descending order
    val elements = value.zip(limit).map { case (v, l) => (v, l) }
    elements.sortWith((a, b) => a._1 > b._1)

    val n = value.length
    val active = scala.collection.mutable.Set[Int]()
    var total = 0L

    for (i <- 0 until n) {
        val (v, l) = elements(i)
        if (active.size < l) {
            // Activate the element
            total += v
            active.add(i)
        }
    }

    total
}
